// Playable numbers (≥4 entries, exclude 41)
const PLAYABLE_NUMBERS = Object.keys(SHIRT_DATA)
  .map(Number)
  .filter(n => SHIRT_DATA[n].length >= 4 && n !== 41);

// Date-seeded number selection
function getTodaysNumber() {
  const now = new Date();
  const seed = now.getFullYear() * 10000 + (now.getMonth() + 1) * 100 + now.getDate();
  return PLAYABLE_NUMBERS[seed % PLAYABLE_NUMBERS.length];
}

// Accent / normalise helper
function normalize(str) {
  return str
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9 \-]/g, "")
    .trim();
}

function matchesPlayer(input, player) {
  const inp = normalize(input);
  if (!inp) return false;
  const nameParts = normalize(player.name).split(" ");
  const surname = nameParts[nameParts.length - 1];
  // Match surname or any alt
  if (inp === surname) return true;
  if (inp === normalize(player.name)) return true;
  for (const alt of player.alts) {
    if (inp === normalize(alt)) return true;
  }
  return false;
}

