// Leaderboard storage key prefix
const KEY_PREFIX = "tgnh_";
const SCORES_KEY = KEY_PREFIX + "scores";

export default function GunnersXI() {
  const shirtNumber = getTodaysNumber();
  const players = SHIRT_DATA[shirtNumber];

  const [phase, setPhase] = useState("intro"); // intro | playing | ended
  const [guess, setGuess] = useState("");
  const [found, setFound] = useState([]); // indices of found players
  const [timeLeft, setTimeLeft] = useState(120);
  const [orderedMode, setOrderedMode] = useState(false);
  const [shake, setShake] = useState(false);
  const [flash, setFlash] = useState(null); // index that just flashed
  const [showLeaderboard, setShowLeaderboard] = useState(false);
  const [scores, setScores] = useState([]);
  const [nameInput, setNameInput] = useState("");
  const [submitted, setSubmitted] = useState(false);
  const [startTime, setStartTime] = useState(null);
  const [elapsed, setElapsed] = useState(0);
  const [loadingScores, setLoadingScores] = useState(false);
  const inputRef = useRef(null);
  const timerRef = useRef(null);

  // Load scores from storage
  const loadScores = useCallback(async () => {
    setLoadingScores(true);
    try {
      const result = await window.storage.get(SCORES_KEY, true);
      if (result && result.value) {
        const parsed = JSON.parse(result.value);
        setScores(Array.isArray(parsed) ? parsed : []);
      }
    } catch (e) {
      setScores([]);
    }
    setLoadingScores(false);
  }, []);

  // Save score to storage
  const saveScore = useCallback(async (name, count, timeTaken) => {
    try {
      let current = [];
      try {
        const result = await window.storage.get(SCORES_KEY, true);
        if (result && result.value) current = JSON.parse(result.value);
      } catch (e) {}
      const today = new Date().toISOString().slice(0, 10);
      const entry = { name, count, timeTaken, shirt: shirtNumber, date: today };
      current.push(entry);
      // Keep only today's scores for leaderboard, sort
      const todayScores = current
        .filter(s => s.shirt === shirtNumber && s.date === today)
        .sort((a, b) => b.count - a.count || a.timeTaken - b.timeTaken);
      // Keep all-time but only show today
      await window.storage.set(SCORES_KEY, JSON.stringify(current), true);
      setScores(todayScores);
    } catch (e) {}
  }, [shirtNumber]);

  // Timer
  useEffect(() => {
    if (phase !== "playing") return;
    timerRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1) {
          clearInterval(timerRef.current);
          setElapsed(prev => 120 - (t - 1));
          setPhase("ended");
          return 0;
        }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, [phase]);

  // Focus input when playing
  useEffect(() => {
    if (phase === "playing" && inputRef.current) {
      inputRef.current.focus();
    }
  }, [phase]);

  function startGame() {
    setFound([]);
    setGuess("");
    setTimeLeft(120);
    setElapsed(0);
    setSubmitted(false);
    setPhase("playing");
    setStartTime(Date.now());
  }

  function giveUp() {
    clearInterval(timerRef.current);
    const secs = Math.round((Date.now() - startTime) / 1000);
    setElapsed(secs);
    setPhase("ended");
  }

  function handleGuess(e) {
    const val = e.target.value;
    setGuess(val);

    // Check each player
    for (let i = 0; i < players.length; i++) {
      if (found.includes(i)) continue;
      if (orderedMode) {
        // Must guess next unfound player (most recent → oldest = index 0 first)
        const nextIdx = players.findIndex((_, idx) => !found.includes(idx));
        if (i !== nextIdx) continue;
      }
      if (matchesPlayer(val, players[i])) {
        setFound(prev => [...prev, i]);
        setFlash(i);
        setTimeout(() => setFlash(null), 600);
        setGuess("");
        // Check if all found
        if (found.length + 1 === players.length) {
          clearInterval(timerRef.current);
          const secs = Math.round((Date.now() - startTime) / 1000);
          setElapsed(secs);
          setTimeout(() => setPhase("ended"), 300);
        }
        return;
      }
    }
  }

  function handleKeyDown(e) {
    if (e.key === "Enter" && guess.trim()) {
      // Check no match found - shake
      let matched = false;
      for (let i = 0; i < players.length; i++) {
        if (!found.includes(i) && matchesPlayer(guess, players[i])) {
          matched = true;
          break;
        }
      }
      if (!matched) {
        setShake(true);
        setTimeout(() => setShake(false), 400);
      }
    }
  }

  async function handleSubmitScore() {
    if (!nameInput.trim()) return;
    const timeTaken = phase === "ended" ? elapsed : 120 - timeLeft;
    await saveScore(nameInput.trim(), found.length, timeTaken);
    setSubmitted(true);
    setShowLeaderboard(true);
  }

  async function handleShowLeaderboard() {
    await loadScores();
    setShowLeaderboard(true);
  }

  const timerPct = (timeLeft / 120) * 100;
  const timerColor = timeLeft > 60 ? "#C8A951" : timeLeft > 20 ? "#f59e0b" : "#EF0107";

  const LOGO_B64 = "";

  // ── INTRO SCREEN ──────────────────────────────────────────────────────────
  if (phase === "intro") {
    return (
      <div style={{ background: "#111110", minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "24px", fontFamily: "'Inter', sans-serif" }}>
        <style>{`
          @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Inter:wght@400;500;600;700&display=swap');
          * { box-sizing: border-box; }
          .btn-primary { background: #EF0107; color: white; border: none; border-radius: 6px; padding: 14px 32px; font-family: 'Bebas Neue', sans-serif; font-size: 22px; letter-spacing: 2px; cursor: pointer; transition: all 0.15s; }
          .btn-primary:hover { background: #c8000a; transform: translateY(-1px); }
          .btn-ghost { background: transparent; color: #C8A951; border: 1px solid #C8A951; border-radius: 6px; padding: 10px 24px; font-family: 'Inter', sans-serif; font-size: 14px; cursor: pointer; transition: all 0.15s; }
          .btn-ghost:hover { background: rgba(200,169,81,0.1); }
        `}</style>

        <img src={`data:image/png;base64,${LOGO_B64}`} alt="Touchline Gunners" style={{ width: 120, marginBottom: 24 }} />
        <h1 style={{ fontFamily: "'Bebas Neue', sans-serif", color: "#EF0107", fontSize: "clamp(40px, 8vw, 72px)", letterSpacing: 4, margin: 0, textAlign: "center", lineHeight: 1 }}>WHO WORE IT?</h1>
        <p style={{ color: "#888", fontSize: 14, margin: "8px 0 32px", textAlign: "center" }}>Daily Arsenal shirt number quiz</p>

        <div style={{ marginBottom: 40, textAlign: "center" }}>
          <p style={{ color: "#aaa", fontSize: 13, marginBottom: 8 }}>Today's number</p>
          <KitSVG number={shirtNumber} size={100} />
          <p style={{ color: "#C8A951", fontFamily: "'Bebas Neue', sans-serif", fontSize: 18, marginTop: 4 }}>
            {players.length} players to find
          </p>
        </div>

        <div style={{ marginBottom: 28, background: "#1a1a19", border: "1px solid #2a2a28", borderRadius: 10, padding: "16px 24px", width: "100%", maxWidth: 380 }}>
          <p style={{ color: "#aaa", fontSize: 13, margin: "0 0 12px", fontWeight: 600, letterSpacing: 1, textTransform: "uppercase" }}>How to play</p>
          <ul style={{ color: "#ccc", fontSize: 13, paddingLeft: 18, margin: 0, lineHeight: 1.8 }}>
            <li>Type surnames to guess players who wore this number</li>
            <li>You have <span style={{ color: "#C8A951", fontWeight: 700 }}>2 minutes</span></li>
            <li>Accents aren't needed — just the surname</li>
            <li>Names match in any order by default</li>
          </ul>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 28 }}>
          <label style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer" }}>
            <div
              onClick={() => setOrderedMode(o => !o)}
              style={{
                width: 44, height: 24, borderRadius: 12,
                background: orderedMode ? "#EF0107" : "#333",
                position: "relative", cursor: "pointer", transition: "background 0.2s"
              }}
            >
              <div style={{
                position: "absolute", top: 2, left: orderedMode ? 22 : 2,
                width: 20, height: 20, borderRadius: "50%", background: "white",
                transition: "left 0.2s"
              }} />
            </div>
            <span style={{ color: "#ccc", fontSize: 14 }}>Ordered mode</span>
          </label>
          <span style={{ color: "#555", fontSize: 12 }}>(most recent → oldest)</span>
        </div>

        <button className="btn-primary" onClick={startGame} style={{ marginBottom: 16 }}>
          START GAME
        </button>
        <button className="btn-ghost" onClick={handleShowLeaderboard}>
          Today's Leaderboard
        </button>

        {showLeaderboard && (
          <LeaderboardModal
            scores={scores}
            loading={loadingScores}
            shirtNumber={shirtNumber}
            onClose={() => setShowLeaderboard(false)}
          />
        )}
      </div>
    );
  }

  // ── PLAYING SCREEN ────────────────────────────────────────────────────────
  if (phase === "playing") {
    return (
      <div style={{ background: "#111110", minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", padding: "16px", fontFamily: "'Inter', sans-serif" }}>
        <style>{`
          @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Inter:wght@400;500;600;700&display=swap');
          * { box-sizing: border-box; }
          @keyframes pop { 0%{transform:scale(1)} 40%{transform:scale(1.08)} 100%{transform:scale(1)} }
          @keyframes shake { 0%,100%{transform:translateX(0)} 20%,60%{transform:translateX(-6px)} 40%,80%{transform:translateX(6px)} }
          .found-flash { animation: pop 0.5s ease; }
          .shake { animation: shake 0.4s ease; }
          .guess-input { background: #1e1e1d; border: 2px solid #333; border-radius: 8px; color: white; font-size: 18px; padding: 12px 16px; width: 100%; outline: none; font-family: 'Inter', sans-serif; transition: border-color 0.15s; }
          .guess-input:focus { border-color: #EF0107; }
          .btn-giveup { background: transparent; color: #666; border: 1px solid #333; border-radius: 6px; padding: 10px 20px; font-family: 'Inter', sans-serif; font-size: 13px; cursor: pointer; transition: all 0.15s; }
          .btn-giveup:hover { border-color: #EF0107; color: #EF0107; }
        `}</style>

        {/* Header */}
        <div style={{ width: "100%", maxWidth: 480, display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <KitSVG number={shirtNumber} size={48} />
            <div>
              <div style={{ fontFamily: "'Bebas Neue', sans-serif", color: "#EF0107", fontSize: 28, letterSpacing: 2, lineHeight: 1 }}>#{shirtNumber}</div>
              <div style={{ color: "#888", fontSize: 12 }}>
                {found.length}/{players.length} found
                {orderedMode && <span style={{ color: "#C8A951", marginLeft: 6 }}>ORDERED</span>}
              </div>
            </div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontFamily: "'Bebas Neue', sans-serif", color: timeLeft <= 20 ? "#EF0107" : "#C8A951", fontSize: 36, lineHeight: 1 }}>
              {Math.floor(timeLeft / 60)}:{String(timeLeft % 60).padStart(2, "0")}
            </div>
          </div>
        </div>

        {/* Timer bar */}
        <div style={{ width: "100%", maxWidth: 480, height: 4, background: "#222", borderRadius: 2, marginBottom: 20, overflow: "hidden" }}>
          <div style={{ height: "100%", width: `${timerPct}%`, background: timerColor, borderRadius: 2, transition: "width 1s linear, background 1s" }} />
        </div>

        {/* Input */}
        <div style={{ width: "100%", maxWidth: 480, marginBottom: 20 }}>
          <input
            ref={inputRef}
            className={`guess-input${shake ? " shake" : ""}`}
            placeholder="Type a surname…"
            value={guess}
            onChange={handleGuess}
            onKeyDown={handleKeyDown}
            autoComplete="off"
            autoCorrect="off"
            autoCapitalize="off"
            spellCheck={false}
          />
        </div>

        {/* Player grid */}
        <div style={{ width: "100%", maxWidth: 480, display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 20 }}>
          {players.map((p, i) => {
            const isFound = found.includes(i);
            const isFlashing = flash === i;
            return (
              <div
                key={i}
                className={isFlashing ? "found-flash" : ""}
                style={{
                  background: isFound ? "rgba(239,1,7,0.15)" : "#1a1a19",
                  border: `1px solid ${isFound ? "#EF0107" : "#2a2a28"}`,
                  borderRadius: 8,
                  padding: "10px 14px",
                  display: "flex",
                  flexDirection: "column",
                  transition: "all 0.3s"
                }}
              >
                {isFound ? (
                  <>
                    <span style={{ color: "#fff", fontWeight: 600, fontSize: 14 }}>{p.name}</span>
                    <span style={{ color: "#C8A951", fontSize: 11, marginTop: 2 }}>{p.years}</span>
                  </>
                ) : (
                  <>
                    <span style={{ color: "#444", fontSize: 14 }}>{"?".repeat(Math.min(p.name.split(" ").pop().length, 8))}</span>
                    <span style={{ color: "#333", fontSize: 11, marginTop: 2 }}>{"_ _ _ _"}</span>
                  </>
                )}
              </div>
            );
          })}
        </div>

        <button className="btn-giveup" onClick={giveUp}>Give Up</button>
      </div>
    );
  }

  // ── ENDED SCREEN ──────────────────────────────────────────────────────────
  if (phase === "ended") {
    const allFound = found.length === players.length;
    const pct = Math.round((found.length / players.length) * 100);
    const timeTaken = elapsed;

    return (
      <div style={{ background: "#111110", minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", padding: "20px", fontFamily: "'Inter', sans-serif" }}>
        <style>{`
          @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Inter:wght@400;500;600;700&display=swap');
          * { box-sizing: border-box; }
          .btn-primary { background: #EF0107; color: white; border: none; border-radius: 6px; padding: 12px 28px; font-family: 'Bebas Neue', sans-serif; font-size: 20px; letter-spacing: 2px; cursor: pointer; transition: all 0.15s; }
          .btn-primary:hover { background: #c8000a; }
          .btn-ghost { background: transparent; color: #C8A951; border: 1px solid #C8A951; border-radius: 6px; padding: 9px 20px; font-family: 'Inter', sans-serif; font-size: 13px; cursor: pointer; transition: all 0.15s; }
          .btn-ghost:hover { background: rgba(200,169,81,0.1); }
          .score-input { background: #1e1e1d; border: 1px solid #333; border-radius: 6px; color: white; font-size: 15px; padding: 10px 14px; outline: none; font-family: 'Inter', sans-serif; flex: 1; }
          .score-input:focus { border-color: #EF0107; }
        `}</style>

        <img src={`data:image/png;base64,${LOGO_B64}`} alt="Touchline Gunners" style={{ width: 60, marginBottom: 12 }} />
        <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", color: allFound ? "#C8A951" : "#EF0107", fontSize: 40, letterSpacing: 3, margin: "0 0 4px" }}>
          {allFound ? "FULL KIT!" : "TIME'S UP"}
        </h2>
        <p style={{ color: "#888", fontSize: 13, marginBottom: 20 }}>
          {allFound ? `All ${players.length} players found in ${Math.floor(timeTaken/60)}:${String(timeTaken%60).padStart(2,"0")}` : `You found ${found.length} of ${players.length} players`}
        </p>

        {/* Score ring */}
        <div style={{ marginBottom: 24, textAlign: "center" }}>
          <svg width={110} height={110} viewBox="0 0 110 110">
            <circle cx={55} cy={55} r={48} fill="none" stroke="#222" strokeWidth={8}/>
            <circle cx={55} cy={55} r={48} fill="none" stroke="#EF0107" strokeWidth={8}
              strokeDasharray={`${2 * Math.PI * 48 * pct / 100} ${2 * Math.PI * 48 * (1 - pct/100)}`}
              strokeDashoffset={2 * Math.PI * 48 * 0.25}
              style={{ transition: "stroke-dasharray 1s ease" }}
            />
            <text x={55} y={52} textAnchor="middle" fontFamily="'Bebas Neue', sans-serif" fontSize={28} fill="white">{found.length}/{players.length}</text>
            <text x={55} y={68} textAnchor="middle" fontFamily="Inter, sans-serif" fontSize={12} fill="#888">FOUND</text>
          </svg>
        </div>

        {/* Results */}
        <div style={{ width: "100%", maxWidth: 480, display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6, marginBottom: 20 }}>
          {players.map((p, i) => {
            const isFound = found.includes(i);
            return (
              <div key={i} style={{
                background: isFound ? "rgba(200,169,81,0.1)" : "rgba(239,1,7,0.08)",
                border: `1px solid ${isFound ? "#C8A951" : "#3a1010"}`,
                borderRadius: 7, padding: "9px 12px"
              }}>
                <span style={{ color: isFound ? "#fff" : "#666", fontWeight: 600, fontSize: 13 }}>{p.name}</span>
                <br/>
                <span style={{ color: isFound ? "#C8A951" : "#444", fontSize: 11 }}>{p.years}</span>
              </div>
            );
          })}
        </div>

        {/* Submit score */}
        {!submitted ? (
          <div style={{ width: "100%", maxWidth: 480, background: "#1a1a19", border: "1px solid #2a2a28", borderRadius: 10, padding: 16, marginBottom: 16 }}>
            <p style={{ color: "#ccc", fontSize: 14, marginBottom: 10, fontWeight: 600 }}>Submit your score</p>
            <div style={{ display: "flex", gap: 8 }}>
              <input
                className="score-input"
                placeholder="Your name…"
                value={nameInput}
                onChange={e => setNameInput(e.target.value)}
                onKeyDown={e => e.key === "Enter" && handleSubmitScore()}
              />
              <button className="btn-primary" onClick={handleSubmitScore} style={{ whiteSpace: "nowrap", fontSize: 16, padding: "10px 20px" }}>
                SUBMIT
              </button>
            </div>
            <p style={{ color: "#555", fontSize: 11, marginTop: 8, marginBottom: 0 }}>Scores are shared with other players</p>
          </div>
        ) : (
          <div style={{ color: "#C8A951", fontSize: 14, marginBottom: 16, textAlign: "center" }}>✓ Score submitted!</div>
        )}

        <div style={{ display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "center" }}>
          <button className="btn-primary" onClick={() => { setPhase("intro"); setShowLeaderboard(false); }}>PLAY AGAIN</button>
          <button className="btn-ghost" onClick={handleShowLeaderboard}>Leaderboard</button>
        </div>

        {showLeaderboard && (
          <LeaderboardModal
            scores={scores}
            loading={loadingScores}
            shirtNumber={shirtNumber}
            onClose={() => setShowLeaderboard(false)}
          />
        )}
      </div>
    );
  }

  return null;
}

function LeaderboardModal({ scores, loading, shirtNumber, onClose }) {
  const today = new Date().toISOString().slice(0, 10);
  const todayScores = scores
    .filter(s => s.shirt === shirtNumber && s.date === today)
    .sort((a, b) => b.count - a.count || a.timeTaken - b.timeTaken)
    .slice(0, 20);

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.85)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100, padding: 20 }}>
      <div style={{ background: "#1a1a19", border: "1px solid #2a2a28", borderRadius: 12, padding: 24, width: "100%", maxWidth: 420, maxHeight: "80vh", overflowY: "auto" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div>
            <h3 style={{ fontFamily: "'Bebas Neue', sans-serif", color: "#EF0107", fontSize: 26, letterSpacing: 2, margin: 0 }}>LEADERBOARD</h3>
            <p style={{ color: "#666", fontSize: 12, margin: 0 }}>Shirt #{shirtNumber} · Today</p>
          </div>
          <button onClick={onClose} style={{ background: "none", border: "none", color: "#666", fontSize: 22, cursor: "pointer", lineHeight: 1 }}>×</button>
        </div>

        {loading ? (
          <p style={{ color: "#888", textAlign: "center", padding: "20px 0" }}>Loading…</p>
        ) : todayScores.length === 0 ? (
          <p style={{ color: "#888", textAlign: "center", padding: "20px 0", fontSize: 14 }}>No scores yet today — be the first!</p>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            {todayScores.map((s, i) => (
              <div key={i} style={{
                display: "flex", alignItems: "center", gap: 12,
                background: i === 0 ? "rgba(200,169,81,0.08)" : "#111110",
                border: `1px solid ${i === 0 ? "#C8A951" : "#252524"}`,
                borderRadius: 8, padding: "10px 14px"
              }}>
                <span style={{ fontFamily: "'Bebas Neue', sans-serif", color: i === 0 ? "#C8A951" : "#555", fontSize: 20, width: 24, textAlign: "center" }}>
                  {i === 0 ? "🥇" : i === 1 ? "🥈" : i === 2 ? "🥉" : i + 1}
                </span>
                <span style={{ color: "#fff", fontWeight: 600, fontSize: 14, flex: 1 }}>{s.name}</span>
                <div style={{ textAlign: "right" }}>
                  <div style={{ color: "#EF0107", fontFamily: "'Bebas Neue', sans-serif", fontSize: 18 }}>{s.count}/{SHIRT_DATA[s.shirt]?.length || "?"}</div>
                  <div style={{ color: "#555", fontSize: 11 }}>
                    {Math.floor(s.timeTaken/60)}:{String(s.timeTaken%60).padStart(2,"0")}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
